final:
module top_module(
    input [3:0] data_in,
    input [1:0] select_signals,
    output reg output_signal
);always @ (*)
begin
    case ({select_signals})
        2'b00: output_signal = data_in[0];
        2'b01: output_signal = data_in[1];
        2'b10: output_signal = data_in[2];
        2'b11: output_signal = data_in[3];
        default: output_signal = 1'bx;
    endcase
end

endmodule
